# Paragraph helper
function Add-Para($bold, $size, $text) {
    $r = '<w:p><w:r><w:rPr><w:rFonts w:eastAsia="SimSun"/>'
    if ($bold) { $r += '<w:b/>' }
    $r += '<w:sz w:val="' + $size + '"/></w:rPr><w:t>' + $text + '</w:t></w:r></w:p>'
    return $r
}

